// Global dependency shims for bundled libraries
const bootstrap = window.bootstrap || {};
const { Collapse, Dropdown, Modal, Offcanvas, Popover, Tab, Toast, Tooltip } = bootstrap;
const ApexCharts = window.ApexCharts;
const Chart = window.Chart;
const Swal = window.Swal;
const Alpine = window.Alpine;

if (Chart && Chart.register) {
  const registry = Chart;
  registry.register(
    registry.CategoryScale || Chart.CategoryScale,
    registry.LinearScale || Chart.LinearScale,
    registry.PointElement || Chart.PointElement,
    registry.LineElement || Chart.LineElement,
    registry.BarElement || Chart.BarElement,
    registry.LineController || Chart.LineController,
    registry.BarController || Chart.BarController,
    registry.DoughnutController || Chart.DoughnutController,
    registry.Title || Chart.Title,
    registry.Tooltip || Chart.Tooltip,
    registry.Legend || Chart.Legend,
    registry.ArcElement || Chart.ArcElement
  );
}


// ===== scripts/utils/icon-manager.js =====
// ==========================================================================
// Icon Manager - Lightweight icon system with tree-shaking
// ==========================================================================

// Option 1: Bootstrap Icons (CSS-based, already included)
class BootstrapIconManager {
  constructor() {
    this.prefix = 'bi';
    this.icons = new Map();
    this.loadCommonIcons();
  }

  loadCommonIcons() {
    // Pre-define commonly used icons for better performance
    this.icons.set('dashboard', 'bi-speedometer2');
    this.icons.set('users', 'bi-people');
    this.icons.set('analytics', 'bi-graph-up');
    this.icons.set('settings', 'bi-gear');
    this.icons.set('notifications', 'bi-bell');
    this.icons.set('search', 'bi-search');
    this.icons.set('menu', 'bi-list');
    this.icons.set('close', 'bi-x');
    this.icons.set('check', 'bi-check');
    this.icons.set('warning', 'bi-exclamation-triangle');
    this.icons.set('info', 'bi-info-circle');
    this.icons.set('success', 'bi-check-circle');
    this.icons.set('error', 'bi-x-circle');
    this.icons.set('arrow-up', 'bi-arrow-up');
    this.icons.set('arrow-down', 'bi-arrow-down');
    this.icons.set('plus', 'bi-plus');
    this.icons.set('edit', 'bi-pencil');
    this.icons.set('delete', 'bi-trash');
    this.icons.set('download', 'bi-download');
    this.icons.set('upload', 'bi-upload');
    this.icons.set('home', 'bi-house');
    this.icons.set('calendar', 'bi-calendar');
    this.icons.set('clock', 'bi-clock');
    this.icons.set('mail', 'bi-envelope');
    this.icons.set('phone', 'bi-telephone');
    this.icons.set('location', 'bi-geo-alt');
    this.icons.set('heart', 'bi-heart');
    this.icons.set('star', 'bi-star');
    this.icons.set('bookmark', 'bi-bookmark');
    this.icons.set('share', 'bi-share');
    this.icons.set('copy', 'bi-clipboard');
    this.icons.set('link', 'bi-link');
    this.icons.set('external', 'bi-box-arrow-up-right');
    this.icons.set('refresh', 'bi-arrow-clockwise');
    this.icons.set('filter', 'bi-funnel');
    this.icons.set('sort', 'bi-sort-down');
    this.icons.set('grid', 'bi-grid');
    this.icons.set('list', 'bi-list-ul');
    this.icons.set('image', 'bi-image');
    this.icons.set('file', 'bi-file-text');
    this.icons.set('folder', 'bi-folder');
    this.icons.set('eye', 'bi-eye');
    this.icons.set('eye-slash', 'bi-eye-slash');
    this.icons.set('lock', 'bi-lock');
    this.icons.set('unlock', 'bi-unlock');
    this.icons.set('user', 'bi-person');
    this.icons.set('team', 'bi-people');
    this.icons.set('crown', 'bi-crown');
    this.icons.set('shield', 'bi-shield-check');
  }

  get(iconName, fallback = 'bi-question-circle') {
    return this.icons.get(iconName) || fallback;
  }

  create(iconName, className = '', attributes = {}) {
    const iconClass = this.get(iconName);
    const element = document.createElement('i');
    element.className = `${iconClass} ${className}`.trim();
    
    Object.entries(attributes).forEach(([key, value]) => {
      element.setAttribute(key, value);
    });

    return element;
  }

  createSVG(iconName, size = 16, className = '') {
    // For future SVG-based icons if needed
    const svg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
    svg.setAttribute('width', size);
    svg.setAttribute('height', size);
    svg.setAttribute('class', className);
    svg.setAttribute('aria-hidden', 'true');
    return svg;
  }
}

// Option 2: Lucide Icons (SVG-based, tree-shakable alternative)
class LucideIconManager {
  constructor() {
    this.icons = new Map();
    this.size = 20;
    this.strokeWidth = 2;
    this.loadLucideIcons();
  }

  async loadLucideIcons() {
    // Tree-shakable Lucide imports (only load what we use) - Optional dependency
    try {
      // Check if lucide is available as optional dependency
      const lucideModule = null;
      
      if (!lucideModule) {
        console.info('Lucide icons not installed, using Bootstrap Icons only');
        return;
      }

      const { 
        BarChart3, 
        Users, 
        Settings, 
        Bell, 
        Search, 
        Menu, 
        X, 
        Check, 
        AlertTriangle,
        Info,
        CheckCircle,
        XCircle,
        ArrowUp,
        ArrowDown,
        Plus,
        Edit,
        Trash2,
        Download,
        Upload,
        Home,
        Calendar,
        Clock,
        Mail,
        Phone,
        MapPin,
        Heart,
        Star,
        Bookmark,
        Share,
        Copy,
        ExternalLink,
        RefreshCw,
        Filter,
        ArrowUpDown,
        Grid3X3,
        List,
        Image,
        FileText,
        Folder,
        Eye,
        EyeOff,
        Lock,
        Unlock,
        User,
        Crown,
        Shield
      } = lucideModule;

      // Map icon names to Lucide components
      this.icons.set('dashboard', BarChart3);
      this.icons.set('users', Users);
      this.icons.set('settings', Settings);
      this.icons.set('notifications', Bell);
      this.icons.set('search', Search);
      this.icons.set('menu', Menu);
      this.icons.set('close', X);
      this.icons.set('check', Check);
      this.icons.set('warning', AlertTriangle);
      this.icons.set('info', Info);
      this.icons.set('success', CheckCircle);
      this.icons.set('error', XCircle);
      this.icons.set('arrow-up', ArrowUp);
      this.icons.set('arrow-down', ArrowDown);
      this.icons.set('plus', Plus);
      this.icons.set('edit', Edit);
      this.icons.set('delete', Trash2);
      this.icons.set('download', Download);
      this.icons.set('upload', Upload);
      this.icons.set('home', Home);
      this.icons.set('calendar', Calendar);
      this.icons.set('clock', Clock);
      this.icons.set('mail', Mail);
      this.icons.set('phone', Phone);
      this.icons.set('location', MapPin);
      this.icons.set('heart', Heart);
      this.icons.set('star', Star);
      this.icons.set('bookmark', Bookmark);
      this.icons.set('share', Share);
      this.icons.set('copy', Copy);
      this.icons.set('external', ExternalLink);
      this.icons.set('refresh', RefreshCw);
      this.icons.set('filter', Filter);
      this.icons.set('sort', ArrowUpDown);
      this.icons.set('grid', Grid3X3);
      this.icons.set('list', List);
      this.icons.set('image', Image);
      this.icons.set('file', FileText);
      this.icons.set('folder', Folder);
      this.icons.set('eye', Eye);
      this.icons.set('eye-slash', EyeOff);
      this.icons.set('lock', Lock);
      this.icons.set('unlock', Unlock);
      this.icons.set('user', User);
      this.icons.set('crown', Crown);
      this.icons.set('shield', Shield);

      console.info('✨ Lucide icons loaded successfully');

    } catch {
      console.info('Lucide icons not available, falling back to Bootstrap Icons only');
    }
  }

  create(iconName, options = {}) {
    const IconComponent = this.icons.get(iconName);
    if (!IconComponent) {
      console.warn(`Icon "${iconName}" not found in Lucide icons`);
      return null;
    }

    const {
      size = this.size,
      strokeWidth = this.strokeWidth,
      className = '',
      color = 'currentColor'
    } = options;

    // Create SVG element
    const svg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
    svg.setAttribute('width', size);
    svg.setAttribute('height', size);
    svg.setAttribute('viewBox', '0 0 24 24');
    svg.setAttribute('fill', 'none');
    svg.setAttribute('stroke', color);
    svg.setAttribute('stroke-width', strokeWidth);
    svg.setAttribute('stroke-linecap', 'round');
    svg.setAttribute('stroke-linejoin', 'round');
    svg.setAttribute('class', `lucide lucide-${iconName} ${className}`.trim());
    svg.setAttribute('aria-hidden', 'true');

    // This would need actual Lucide SVG paths - simplified for demo
    const path = document.createElementNS('http://www.w3.org/2000/svg', 'path');
    svg.appendChild(path);

    return svg;
  }
}

// Main Icon Manager (configurable)
class IconManager {
  constructor(provider = 'bootstrap') {
    this.provider = provider;
    this.manager = provider === 'lucide' 
      ? new LucideIconManager() 
      : new BootstrapIconManager();
  }

  // Unified API for both providers
  get(iconName) {
    return this.manager.get ? this.manager.get(iconName) : iconName;
  }

  create(iconName, options = {}) {
    if (this.provider === 'lucide') {
      return this.manager.create(iconName, options);
    } else {
      // Bootstrap Icons
      const { className = '', ...attributes } = options;
      return this.manager.create(iconName, className, attributes);
    }
  }

  // Utility method to replace icon in existing element
  replaceIcon(element, iconName, options = {}) {
    if (this.provider === 'bootstrap') {
      const iconClass = this.get(iconName);
      element.className = element.className.replace(/bi-[\w-]+/g, '');
      element.classList.add(iconClass);
    } else {
      const newIcon = this.create(iconName, options);
      if (newIcon && element.parentNode) {
        element.parentNode.replaceChild(newIcon, element);
      }
    }
  }

  // Batch icon loading for better performance
  preloadIcons(iconNames = []) {
    iconNames.forEach(name => {
      this.create(name);
    });
  }

  // Switch provider dynamically
  switchProvider(provider) {
    this.provider = provider;
    this.manager = provider === 'lucide' 
      ? new LucideIconManager() 
      : new BootstrapIconManager();
  }
}

// Export default instance
const iconManager = new IconManager('bootstrap');

// Export for easy switching
const switchToLucide = () => {
  iconManager.switchProvider('lucide');
};

const switchToBootstrap = () => {
  iconManager.switchProvider('bootstrap');
};


// ===== scripts/utils/theme-manager.js =====
// ==========================================================================
// Theme Manager - Handle dark/light mode switching
// ==========================================================================

class ThemeManager {
  constructor() {
    this.currentTheme = resolveInitialTheme();
    this.themeToggleButtons = [];
    this.init();
  }

  init() {
    // Set initial theme
    this.setTheme(this.currentTheme);
    
    // Listen for system theme changes
    window.matchMedia('(prefers-color-scheme: dark)')
      .addEventListener('change', (e) => {
        if (!this.getStoredTheme()) {
          this.setTheme(e.matches ? 'dark' : 'light');
        }
      });
  }

  getStoredTheme() {
    return localStorage.getItem('theme');
  }

  getPreferredTheme() {
    return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
  }

  setTheme(theme) {
    document.documentElement.setAttribute('data-bs-theme', theme);
    localStorage.setItem('theme', theme);
    this.currentTheme = theme;
    this.updateThemeIcons();
  }

  toggleTheme() {
    const newTheme = this.currentTheme === 'light' ? 'dark' : 'light';
    this.setTheme(newTheme);
  }

  updateThemeIcons() {
    const lightIcons = document.querySelectorAll('.theme-icon-light');
    const darkIcons = document.querySelectorAll('.theme-icon-dark');
    
    if (this.currentTheme === 'dark') {
      lightIcons.forEach(icon => icon.classList.add('d-none'));
      darkIcons.forEach(icon => icon.classList.remove('d-none'));
    } else {
      lightIcons.forEach(icon => icon.classList.remove('d-none'));
      darkIcons.forEach(icon => icon.classList.add('d-none'));
    }
  }

  getCurrentTheme() {
    return this.currentTheme;
  }
}

function resolveInitialTheme() {
  try {
    const stored = localStorage.getItem('theme');
    if (stored === 'dark' || stored === 'light') return stored;
  } catch (e) {
    /* private mode */
  }
  const attr = document.documentElement.getAttribute('data-bs-theme');
  if (attr === 'dark' || attr === 'light') return attr;
  return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
}

function resolveInitialDir() {
  try {
    const stored = localStorage.getItem('textDirection');
    if (stored === 'rtl' || stored === 'ltr') return stored;
  } catch (e) {
    /* private mode */
  }
  const attr = document.documentElement.getAttribute('dir');
  if (attr === 'rtl' || attr === 'ltr') return attr;
  return 'ltr';
}


// ===== scripts/utils/notifications.js =====
// ==========================================================================
// Notification Manager - Advanced toast and modal notifications
// ==========================================================================



class NotificationManager {
  constructor() {
    this.container = document.getElementById('toast-container') || this.createToastContainer();
    this.defaultDuration = 5000;
    this.activeToasts = new Set();
    this.init();
  }

  init() {
    // Create toast container if it doesn't exist
    if (!this.container) {
      this.container = this.createToastContainer();
    }

    // Configure SweetAlert2 defaults
    this.configureSweetAlert();
  }

  createToastContainer() {
    const container = document.createElement('div');
    container.id = 'toast-container';
    container.className = 'position-fixed top-0 end-0 p-3';
    container.style.zIndex = '11';
    container.setAttribute('aria-live', 'polite');
    container.setAttribute('aria-atomic', 'true');
    document.body.appendChild(container);
    return container;
  }

  configureSweetAlert() {
    Swal.mixin({
      customClass: {
        confirmButton: 'btn btn-primary me-2',
        cancelButton: 'btn btn-secondary',
        popup: 'rounded-3 shadow-lg',
        title: 'fs-4 fw-bold',
        content: 'text-muted'
      },
      buttonsStyling: false,
      reverseButtons: true,
      focusConfirm: false,
      allowOutsideClick: true,
      allowEscapeKey: true,
      showCloseButton: true
    });
  }

  // Toast Notifications
  show(message, type = 'info', options = {}) {
    const toastConfig = {
      message,
      type,
      duration: options.duration || this.defaultDuration,
      persistent: options.persistent || false,
      action: options.action || null,
      icon: options.icon || this.getIconForType(type)
    };

    const toast = this.createToast(toastConfig);
    this.container.appendChild(toast);

    const bsToast = new Toast(toast, {
      autohide: !toastConfig.persistent,
      delay: toastConfig.duration
    });

    this.activeToasts.add(bsToast);

    // Remove from active toasts when hidden
    toast.addEventListener('hidden.bs.toast', () => {
      this.activeToasts.delete(bsToast);
      toast.remove();
    });

    bsToast.show();
    return bsToast;
  }

  createToast(config) {
    const toastId = `toast-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
    const toast = document.createElement('div');
    toast.className = `toast align-items-center text-bg-${config.type} border-0`;
    toast.id = toastId;
    toast.role = 'alert';
    toast.setAttribute('aria-live', 'assertive');
    toast.setAttribute('aria-atomic', 'true');

    const closeButton = config.persistent ? '' : `
      <button type="button" class="btn-close btn-close-white me-2 m-auto" data-bs-dismiss="toast" aria-label="Close"></button>
    `;

    const actionButton = config.action ? `
      <button type="button" class="btn btn-sm btn-outline-light me-2" onclick="${config.action.handler}">
        ${config.action.text}
      </button>
    ` : '';

    toast.innerHTML = `
      <div class="d-flex">
        <div class="toast-body d-flex align-items-center">
          <i class="${config.icon} me-2"></i>
          <span class="flex-grow-1">${config.message}</span>
          ${actionButton}
        </div>
        ${closeButton}
      </div>
    `;

    return toast;
  }

  getIconForType(type) {
    const icons = {
      success: 'bi bi-check-circle-fill',
      error: 'bi bi-exclamation-triangle-fill',
      warning: 'bi bi-exclamation-triangle-fill',
      info: 'bi bi-info-circle-fill',
      primary: 'bi bi-info-circle-fill',
      secondary: 'bi bi-info-circle-fill',
      danger: 'bi bi-exclamation-triangle-fill',
      light: 'bi bi-info-circle-fill',
      dark: 'bi bi-info-circle-fill'
    };
    return icons[type] || icons.info;
  }

  // Convenience methods
  success(message, options = {}) {
    return this.show(message, 'success', options);
  }

  error(message, options = {}) {
    return this.show(message, 'danger', options);
  }

  warning(message, options = {}) {
    return this.show(message, 'warning', options);
  }

  info(message, options = {}) {
    return this.show(message, 'info', options);
  }

  // SweetAlert2 Modal Notifications
  async confirm(options = {}) {
    const defaultOptions = {
      title: 'Are you sure?',
      text: 'This action cannot be undone.',
      icon: 'warning',
      showCancelButton: true,
      confirmButtonText: 'Yes, proceed',
      cancelButtonText: 'Cancel'
    };

    const result = await Swal.fire({
      ...defaultOptions,
      ...options
    });

    return result.isConfirmed;
  }

  async prompt(options = {}) {
    const defaultOptions = {
      title: 'Enter value',
      input: 'text',
      showCancelButton: true,
      confirmButtonText: 'Submit',
      cancelButtonText: 'Cancel',
      inputValidator: (value) => {
        if (!value) {
          return 'Please enter a value';
        }
      }
    };

    const result = await Swal.fire({
      ...defaultOptions,
      ...options
    });

    return result.isConfirmed ? result.value : null;
  }

  async alert(message, type = 'info', title = '') {
    const icons = {
      success: 'success',
      error: 'error',
      warning: 'warning',
      info: 'info'
    };

    await Swal.fire({
      title: title,
      text: message,
      icon: icons[type] || 'info',
      confirmButtonText: 'OK'
    });
  }

  async showLoading(message = 'Loading...') {
    Swal.fire({
      title: message,
      allowOutsideClick: false,
      allowEscapeKey: false,
      showConfirmButton: false,
      willOpen: () => {
        Swal.showLoading();
      }
    });
  }

  hideLoading() {
    Swal.close();
  }

  // Progress notification
  async showProgress(title, onProgress) {
    await Swal.fire({
      title: title,
      html: `
        <div class="progress mb-3">
          <div class="progress-bar" role="progressbar" style="width: 0%" aria-valuenow="0" aria-valuemin="0" aria-valuemax="100"></div>
        </div>
        <div id="progress-text">Starting...</div>
      `,
      allowOutsideClick: false,
      showConfirmButton: false,
      willOpen: () => {
        const progressBar = Swal.getHtmlContainer().querySelector('.progress-bar');
        const progressText = Swal.getHtmlContainer().querySelector('#progress-text');

        if (onProgress && typeof onProgress === 'function') {
          onProgress((step, text) => {
            progressBar.style.width = `${step}%`;
            progressBar.setAttribute('aria-valuenow', step);
            if (text) {
              progressText.textContent = text;
            }

            if (step >= 100) {
              setTimeout(() => {
                Swal.close();
                this.success('Operation completed successfully!');
              }, 500);
            }
          });
        }
      }
    });
  }

  // Bulk operations
  clearAll() {
    this.activeToasts.forEach(toast => {
      toast.hide();
    });
    this.activeToasts.clear();
  }

  // Real-time notifications (for WebSocket/SSE integration)
  handleRealTimeNotification(data) {
    const { type, message, priority = 'normal', persistent = false } = data;
    
    const options = {
      persistent: priority === 'high' || persistent,
      duration: priority === 'high' ? 10000 : this.defaultDuration
    };

    // Add sound for high priority notifications
    if (priority === 'high') {
      this.playNotificationSound();
    }

    this.show(message, type, options);
  }

  playNotificationSound() {
    // Create audio element for notification sound
    const audio = new Audio('data:audio/wav;base64,UklGRnoGAABXQVZFZm10IBAAAAABAAEAQB8AAEAfAAABAAgAZGF0YQoGAACBhYqFbF1fdJivrJBhNjVgodDbq2EcBj+a2/LDciUFLIHO8tiJNwgZaLvt559NEAxQp+PwtmMcBjiR1/LMeSwFJHfH8N2QQAoUXrTp66hVFApGn+DyvmMcBjiS2O/FeCkFKXnJ8N+PQAoSXrTp6qpTFAlEnt//wUfZBBmBzOvQDh8VHH/H7N4=' );
    audio.volume = 0.3;
    audio.play().catch(() => {
      // Ignore audio play errors (browser restrictions)
    });
  }

  // Activity feed integration
  addToActivityFeed(notification) {
    const activityFeed = document.querySelector('.activity-feed');
    if (!activityFeed) return;

    const activityItem = document.createElement('div');
    activityItem.className = 'activity-item';
    activityItem.innerHTML = `
      <div class="activity-icon bg-${notification.type} bg-opacity-10 text-${notification.type}">
        <i class="${this.getIconForType(notification.type)}"></i>
      </div>
      <div class="activity-content">
        <p class="mb-1">${notification.message}</p>
        <small class="text-muted">Just now</small>
      </div>
    `;

    activityFeed.insertBefore(activityItem, activityFeed.firstChild);

    // Limit activity feed to 10 items
    const items = activityFeed.querySelectorAll('.activity-item');
    if (items.length > 10) {
      items[items.length - 1].remove();
    }
  }

  // Browser notification API
  async requestNotificationPermission() {
    if ('Notification' in window) {
      const permission = await Notification.requestPermission();
      return permission === 'granted';
    }
    return false;
  }

  showBrowserNotification(title, options = {}) {
    if ('Notification' in window && Notification.permission === 'granted') {
      const notification = new Notification(title, {
        icon: '/favicon.ico',
        badge: '/favicon.ico',
        ...options
      });

      // Auto close after 5 seconds
      setTimeout(() => {
        notification.close();
      }, 5000);

      return notification;
    }
  }
}


// ===== scripts/components/sidebar.js =====
// ==========================================================================
// Sidebar Manager - Handle sidebar toggle and state
// ==========================================================================

class SidebarManager {
  constructor() {
    this.wrapper = document.getElementById('admin-wrapper');
    this.toggleButton = document.querySelector('[data-sidebar-toggle]');
    
    // If essential elements aren't found, do nothing.
    if (!this.wrapper || !this.toggleButton) {
      console.warn('SidebarManager: Essential elements (wrapper or toggle button) not found. Manager will be inactive.');
      return;
    }

    this.init();
  }

  init() {
    // Set initial state from localStorage on page load.
    const isCollapsed = localStorage.getItem('sidebar-collapsed') === 'true';
    if (isCollapsed) {
      this.wrapper.classList.add('sidebar-collapsed');
      this.toggleButton.classList.add('is-active');
    }
  }

  toggle() {
    // The DOM is the single source of truth.
    const isCurrentlyCollapsed = this.wrapper.classList.contains('sidebar-collapsed');

    if (isCurrentlyCollapsed) {
      this.expand();
    } else {
      this.collapse();
    }
  }

  collapse() {
    this.wrapper.classList.add('sidebar-collapsed');
    this.toggleButton.classList.add('is-active');
    localStorage.setItem('sidebar-collapsed', 'true');
  }

  expand() {
    this.wrapper.classList.remove('sidebar-collapsed');
    this.toggleButton.classList.remove('is-active');
    localStorage.setItem('sidebar-collapsed', 'false');
  }
}


